// Extrai lista de funis ativos com id e nome
const data = $input.first().json;
const funnels = (data.funnels || []).filter(f => f.is_active);

if (funnels.length === 0) return [];

return funnels.map(f => ({
  json: { funnel_id: f.id, funnel_nome: f.nome }
}));

// Analisa TODOS os boards e encontra leads estagnados
// Usa dias_limite de cada etapa (dinâmico, configurado no funil)

const allBoards = $input.all();
const estagnados = [];

for (const boardItem of allBoards) {
  const board = boardItem.json;
  const funilNome = board.funnel?.nome || 'Desconhecido';

  for (const stage of (board.stages || [])) {
    const limiteDias = stage.dias_limite || 7;

    for (const lead of (stage.leads || [])) {
      // Usa entry_updated_at (última movimentação de etapa)
      const dataRef = lead.entry_updated_at || lead.entry_created_at;
      if (!dataRef) continue;

      const dias = Math.floor(
        (Date.now() - new Date(dataRef).getTime()) / (1000*60*60*24)
      );

      if (dias >= limiteDias) {
        estagnados.push({
          nome: lead.nome,
          funil: funilNome,
          etapa: stage.nome,
          dias: dias,
          limite: limiteDias,
          responsavel: lead.responsavel_nome || 'Sem responsável'
        });
      }
    }
  }
}

if (estagnados.length === 0) return [];

// Agrupa por funil > etapa para o relatório
const grupos = {};
for (const l of estagnados) {
  const chave = `${l.funil} > ${l.etapa}`;
  if (!grupos[chave]) grupos[chave] = [];
  grupos[chave].push(l);
}

// Monta mensagem formatada
let msg = '';
for (const [grupo, leads] of Object.entries(grupos)) {
  msg += `\n📍 ${grupo}:\n`;
  for (const l of leads) {
    msg += `  • ${l.nome} — ${l.dias} dias — ${l.responsavel}\n`;
  }
}
msg += `\nTotal: ${estagnados.length} lead(s)`;

return [{
  json: {
    total: estagnados.length,
    mensagem: msg,
    detalhes: estagnados
  }
}];
